def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 100)))
    code = [rng.randint(1, 100) for _ in range(n)]
    if n == 1:
        k = 0
    else:
        k = rng.randint(-(n - 1), n - 1)
    return [code, k]

