class Solution:
    def decrypt(self, code, k):
        n = len(code)
        if k == 0:
            return [0] * n
        ext = code + code
        prefix = [0] * (2 * n + 1)
        for i in range(2 * n):
            prefix[i + 1] = prefix[i] + ext[i]
        result = [0] * n
        for i in range(n):
            if k > 0:
                start = i + 1
                end = i + k
            else:
                start = i + n + k
                end = i + n - 1
            result[i] = prefix[end + 1] - prefix[start]
        return result

