var decrypt = function(code, k) {
    const n = code.length;
    if (k === 0) return new Array(n).fill(0);
    const ext = code.concat(code);
    const prefix = new Array(2 * n + 1).fill(0);
    for (let i = 0; i < 2 * n; i++) {
        prefix[i + 1] = prefix[i] + ext[i];
    }
    const result = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let start, end;
        if (k > 0) {
            start = i + 1;
            end = i + k;
        } else {
            start = i + n + k;
            end = i + n - 1;
        }
        result[i] = prefix[end + 1] - prefix[start];
    }
    return result;
};
